import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  const deletePhoto = () => {
    if (window.confirm("사진을 삭제하시겠습니까?")) {
      setPhoto(null);
    }
  };

  return (
    <div style={containerStyle}>
      {/* 상단 컨트롤 바 */}
      <div style={topBarStyle}>
        <span style={iconStyle}>⚡️</span>
        <span style={textLogoStyle}>PHOTO</span>
        <span style={iconStyle}>⚙️</span>
      </div>

      {/* 메인 뷰파인더 (사진 표시 영역) */}
      <div style={viewFinderStyle}>
        {photo ? (
          <img src={photo} alt="Result" style={imageStyle} />
        ) : (
          <div style={emptyViewStyle}>
            <div style={focusBracketStyle}></div>
            <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "14px" }}>
              READY
            </p>
          </div>
        )}
      </div>

      {/* 하단 컨트롤 레이아웃 */}
      <div style={bottomControlsStyle}>
        <div style={modeSelectorStyle}>
          <span>SLO-MO</span>
          <span style={{ color: "#FFD60A" }}>PHOTO</span>
          <span>VIDEO</span>
        </div>

        <div style={shutterSectionStyle}>
          {/* 왼쪽: 앨범 미리보기 (사진이 있을 때만 삭제 아이콘으로 활용) */}
          <div style={thumbnailStyle} onClick={photo ? deletePhoto : null}>
            {photo ? (
              <span style={{ color: "white", fontSize: "20px" }}>🗑️</span>
            ) : (
              <div style={emptyThumbStyle} />
            )}
          </div>

          {/* 중앙: 촬영 버튼 (셔터) */}
          <div style={shutterOuterStyle} onClick={takePhoto}>
            <div style={shutterInnerStyle} />
          </div>

          {/* 오른쪽: 카메라 전환 아이콘 (데모용) */}
          <div style={thumbnailStyle}>
            <span style={{ color: "white", fontSize: "24px" }}>🔄</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// --- 실제 앱 같은 스타일 정의 ---

const containerStyle = {
  backgroundColor: "#000", // 카메라 앱은 기본적으로 블랙
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  color: "#fff",
  fontFamily: "-apple-system, BlinkMacSystemFont, sans-serif",
  overflow: "hidden",
};

const topBarStyle = {
  height: "60px",
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  padding: "0 20px",
  fontSize: "18px",
};

const textLogoStyle = {
  letterSpacing: "2px",
  fontSize: "14px",
  fontWeight: "600",
};

const iconStyle = { fontSize: "20px", cursor: "pointer" };

const viewFinderStyle = {
  flex: 1,
  backgroundColor: "#1c1c1e",
  margin: "0 10px",
  borderRadius: "15px", // 최신 아이폰 느낌의 라운딩
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  position: "relative",
  overflow: "hidden",
};

const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };

const emptyViewStyle = { textAlign: "center" };

const focusBracketStyle = {
  width: "80px",
  height: "80px",
  border: "1px solid rgba(255, 214, 10, 0.5)", // 초점 사각형
  position: "absolute",
  top: "50%",
  left: "50%",
  transform: "translate(-50%, -50%)",
};

const bottomControlsStyle = {
  height: "180px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  justifyContent: "center",
};

const modeSelectorStyle = {
  display: "flex",
  gap: "20px",
  fontSize: "13px",
  fontWeight: "bold",
  marginBottom: "25px",
  color: "#fff",
};

const shutterSectionStyle = {
  width: "100%",
  display: "flex",
  justifyContent: "space-around",
  alignItems: "center",
  padding: "0 30px",
};

const shutterOuterStyle = {
  width: "76px",
  height: "76px",
  borderRadius: "50%",
  border: "4px solid #fff",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  cursor: "pointer",
};

const shutterInnerStyle = {
  width: "60px",
  height: "60px",
  borderRadius: "50%",
  backgroundColor: "#fff",
};

const thumbnailStyle = {
  width: "45px",
  height: "45px",
  borderRadius: "8px",
  backgroundColor: "#333",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  overflow: "hidden",
  cursor: "pointer",
};

const emptyThumbStyle = {
  width: "100%",
  height: "100%",
  background: "linear-gradient(45deg, #333, #555)",
};

export default App;
